UPDATE om_auth_group_m
   SET is_deleted = true
     , updated_at = CURRENT_TIMESTAMP
     , updated_by = #{userId}
 WHERE auth_group_cd = #{authGroupCd}
   AND COALESCE(is_deleted, false) = false

UPDATE om_auth_group_m
   SET auth_group_nm = #{authGroupNm}
     , remark = #{remark,jdbcType=VARCHAR}
     , updated_at = CURRENT_TIMESTAMP
     , updated_by = #{userId}
 WHERE auth_group_cd = #{authGroupCd}
   AND COALESCE(is_deleted, false) = false
